//! OCEL 2.0 Accumulator — generated by ggen lsp-max pack
//! Source of truth: schema/domain.ttl | Run `ggen sync` to regenerate
//! Status: CANDIDATE — RFC C accumulation not yet admission-bound
//!
//! Object-Centric Event Log (OCEL) 2.0 event accumulator for the FlushCoordinator.
//! Collects events from all LSP operations (initialize, textDocument/*, workspace/*)
//! into a cumulative buffer that can be exported for process-mining analysis.

use serde_json::{json, Value};
use std::sync::{Arc, Mutex};
use std::sync::atomic::{AtomicU64, Ordering};

/// Event id counter — each accumulated event gets a unique, monotonic id.
pub type EventIdCounter = Arc<AtomicU64>;

/// OCEL 2.0 event accumulator buffer — thread-safe mutable Vec of events.
pub type OcelEventBuffer = Arc<Mutex<Vec<Value>>>;

/// Accumulated event fingerprint: (activity_name, object_id, timestamp).
/// Used for deduplication and event tracing.
#[derive(Debug, Clone, PartialEq, Eq, Hash)]
pub struct EventFingerprint {
    pub activity: String,
    pub object_id: Option<String>,
    pub timestamp: String,
}

/// Event accumulation result: the generated event JSON + metadata.
#[derive(Debug, Clone)]
pub struct AccumulatedEvent {
    pub id: String,
    pub activity: String,
    pub timestamp: String,
    pub relationships: Vec<OcelRelationship>,
    pub attributes: serde_json::Map<String, Value>,
}

/// OCEL 2.0 relationship: a typed, qualified edge to an object id.
#[derive(Debug, Clone)]
pub struct OcelRelationship {
    pub object_id: String,
    pub qualifier: Option<String>,
}

impl AccumulatedEvent {
    /// Serialize to OCEL 2.0 event JSON format.
    pub fn to_json(&self) -> Value {
        let mut relationships = Vec::new();
        for rel in &self.relationships {
            let mut rel_obj = serde_json::Map::new();
            rel_obj.insert("objectId".to_string(), Value::String(rel.object_id.clone()));
            if let Some(q) = &rel.qualifier {
                rel_obj.insert("qualifier".to_string(), Value::String(q.clone()));
            }
            relationships.push(Value::Object(rel_obj));
        }

        let mut event = self.attributes.clone();
        event.insert("id".to_string(), Value::String(self.id.clone()));
        event.insert("type".to_string(), Value::String(self.activity.clone()));
        event.insert("time".to_string(), Value::String(self.timestamp.clone()));
        event.insert("relationships".to_string(), Value::Array(relationships));

        Value::Object(event)
    }
}

/// OcelAccumulator — manages event collection for the FlushCoordinator.
pub struct OcelAccumulator {
    event_counter: EventIdCounter,
    buffer: OcelEventBuffer,
    /// Deduplication set — tracks (activity, object_id, timestamp) fingerprints.
    /// Set-based membership prevents duplicate events from accumulating.
    seen_fingerprints: Arc<Mutex<std::collections::HashSet<EventFingerprint>>>,
}

impl OcelAccumulator {
    /// Create a new accumulator with empty buffer and counter at 0.
    pub fn new() -> Self {
        Self {
            event_counter: Arc::new(AtomicU64::new(0)),
            buffer: Arc::new(Mutex::new(Vec::new())),
            seen_fingerprints: Arc::new(Mutex::new(std::collections::HashSet::new())),
        }
    }

    /// Accumulate a single event. Deduplicates on (activity, object_id, timestamp).
    /// Returns `true` if the event was added, `false` if it was a duplicate.
    pub fn accumulate(&self, event: AccumulatedEvent) -> bool {
        let fingerprint = EventFingerprint {
            activity: event.activity.clone(),
            object_id: event.relationships.first().map(|r| r.object_id.clone()),
            timestamp: event.timestamp.clone(),
        };

        let mut seen = self.seen_fingerprints.lock().unwrap_or_else(|p| p.into_inner());
        if seen.contains(&fingerprint) {
            return false;
        }
        seen.insert(fingerprint);

        let json_event = event.to_json();
        let mut buf = self.buffer.lock().unwrap_or_else(|p| p.into_inner());
        buf.push(json_event);

        true
    }

    /// Accumulate a raw JSON event (for integration with CompositorReceipt).
    /// Deduplicates based on the event's (type, first-objectId, time) fields.
    pub fn accumulate_json(&self, json_event: &Value) -> bool {
        let activity = json_event
            .get("type")
            .and_then(|v| v.as_str())
            .unwrap_or("unknown")
            .to_string();

        let timestamp = json_event
            .get("time")
            .and_then(|v| v.as_str())
            .unwrap_or("1970-01-01T00:00:00Z")
            .to_string();

        let object_id = json_event
            .get("relationships")
            .and_then(|v| v.as_array())
            .and_then(|arr| arr.first())
            .and_then(|rel| rel.get("objectId"))
            .and_then(|v| v.as_str())
            .map(String::from);

        let fingerprint = EventFingerprint {
            activity,
            object_id,
            timestamp,
        };

        let mut seen = self.seen_fingerprints.lock().unwrap_or_else(|p| p.into_inner());
        if seen.contains(&fingerprint) {
            return false;
        }
        seen.insert(fingerprint);

        let mut buf = self.buffer.lock().unwrap_or_else(|p| p.into_inner());
        buf.push(json_event.clone());

        true
    }

    /// Drain all accumulated events. Returns the buffer contents and clears it.
    pub fn drain(&self) -> Vec<Value> {
        let mut buf = self.buffer.lock().unwrap_or_else(|p| p.into_inner());
        buf.drain(..).collect()
    }

    /// Get the current event count (snapshot, non-destructive).
    pub fn len(&self) -> usize {
        let buf = self.buffer.lock().unwrap_or_else(|p| p.into_inner());
        buf.len()
    }

    /// Check if the buffer is empty.
    pub fn is_empty(&self) -> bool {
        self.len() == 0
    }

    /// Get the next event id (monotonic counter).
    pub fn next_event_id(&self) -> String {
        let id = self.event_counter.fetch_add(1, Ordering::SeqCst);
        format!("event-{}", id)
    }

    /// Export accumulated events as an OCEL 2.0 JSON structure.
    /// Returns the accumulated OCEL 2.0 log snapshot with current events and an empty objects array.
    pub fn export_ocel(&self) -> Value {
        let events = self.buffer.lock().unwrap_or_else(|p| p.into_inner());
        json!({
            "events": events.clone(),
            "objects": []
        })
    }

    /// Clear all state (events and fingerprints). Use sparingly; typically for testing.
    pub fn clear(&self) {
        let mut buf = self.buffer.lock().unwrap_or_else(|p| p.into_inner());
        buf.clear();

        let mut seen = self.seen_fingerprints.lock().unwrap_or_else(|p| p.into_inner());
        seen.clear();

        self.event_counter.store(0, Ordering::SeqCst);
    }

    /// Admit the exported OCEL log through wasm4pm-compat.
    /// Validates the OCEL structure through wasm4pm_compat::LinkedOcel,
    /// and returns a JSON result confirming admission or describing the refusal.
    /// Returns the JSON string or an error message if admission fails.
    #[cfg(feature = "wasm4pm-compat")]
    pub fn admit_ocel_export(&self) -> Result<String, String> {
        use wasm4pm_compat::admission::Admit;
        use wasm4pm_compat::evidence::Evidence;
        use wasm4pm_compat::ocel::{LinkedOcel, OcelLog, OcelEvent, Object, EventObjectLink};

        let ocel_value = self.export_ocel();

        // Extract events and objects from the JSON value
        let events_json = ocel_value.get("events")
            .and_then(|v| v.as_array())
            .ok_or("Invalid OCEL structure: missing or invalid 'events' array")?;

        let objects_json = ocel_value.get("objects")
            .and_then(|v| v.as_array())
            .ok_or("Invalid OCEL structure: missing or invalid 'objects' array")?;

        // Build OcelEvent objects from JSON events
        let mut events = Vec::new();
        for event_val in events_json {
            if let Some(event_map) = event_val.as_object() {
                if let Some(event_id) = event_map.get("id").and_then(|v| v.as_str()) {
                    if let Some(event_type) = event_map.get("type").and_then(|v| v.as_str()) {
                        events.push(OcelEvent::new(event_id, event_type));
                    }
                }
            }
        }

        // Build Object instances from JSON objects (or use empty if none provided)
        let mut objects = Vec::new();
        for obj_val in objects_json {
            if let Some(obj_map) = obj_val.as_object() {
                if let Some(obj_id) = obj_map.get("id").and_then(|v| v.as_str()) {
                    if let Some(obj_type) = obj_map.get("type").and_then(|v| v.as_str()) {
                        objects.push(Object::new(obj_id, obj_type));
                    }
                }
            }
        }

        // Build EventObjectLink objects from event relationships
        let mut e2o_links = Vec::new();
        for event_val in events_json {
            if let Some(event_map) = event_val.as_object() {
                if let Some(event_id) = event_map.get("id").and_then(|v| v.as_str()) {
                    if let Some(rels) = event_map.get("relationships").and_then(|v| v.as_array()) {
                        for rel_val in rels {
                            if let Some(rel_map) = rel_val.as_object() {
                                if let Some(obj_id) = rel_map.get("objectId").and_then(|v| v.as_str()) {
                                    e2o_links.push(EventObjectLink::new(event_id, obj_id));
                                }
                            }
                        }
                    }
                }
            }
        }

        // Create the OcelLog and wrap it in Evidence
        let ocel_log = OcelLog::new(objects, events, e2o_links, [], []);
        let raw_evidence = Evidence::raw(ocel_log);

        // Attempt to admit the log through LinkedOcel
        match LinkedOcel::admit(raw_evidence) {
            Ok(admission) => {
                // Admission successful — serialize the result
                let result = serde_json::json!({
                    "status": "admitted",
                    "log_events": admission.value.events().len(),
                    "log_objects": admission.value.objects().len(),
                });
                serde_json::to_string(&result)
                    .map_err(|e| format!("Failed to serialize admission result: {}", e))
            }
            Err(refusal) => {
                // Admission refused — return the refusal reason
                Err(format!("OCEL admission refused: {:?}", refusal.reason))
            }
        }
    }
}

impl Default for OcelAccumulator {
    fn default() -> Self {
        Self::new()
    }
}

